const defaultQueries = [
  'assortment planning',
  'assortment strategy',
  'buying strategy',
  'collection merchandising',
  'sell-through analytics',
  'merchandising blind spots',
  'retail transformation',
  'experiential retail',
  'editorial retail',
  'clienteling',
  'product customer mismatch',
  'identity mismatch',
  'expectation mismatch',
  'limitations of sell-through analytics'
];

const readJsonEnv = (value, fallback) => {
  if (!value) return fallback;
  try {
    const parsed = JSON.parse(value);
    if (Array.isArray(parsed)) return parsed.filter(Boolean).map((entry) => String(entry).trim()).filter(Boolean);
  } catch {
    return fallback;
  }
  return fallback;
};

const queries = readJsonEnv($env.SEARCH_QUERIES_JSON, defaultQueries);
const maxPosts = Number($env.APIFY_MAX_POSTS || 5);
const maxReactions = Number($env.APIFY_MAX_REACTIONS || 5);
const delaySeconds = Number($env.APIFY_BETWEEN_QUERY_SECONDS || 7);

return queries.map((searchQuery, index) => ({
  json: {
    searchQuery,
    queryIndex: index + 1,
    maxPosts,
    maxReactions,
    postNestedComments: false,
    postNestedReactions: false,
    scrapeComments: false,
    scrapeReactions: false,
    delaySeconds
  }
}));

const delaySeconds = Number($env.APIFY_BETWEEN_QUERY_SECONDS || 7);
const delayMs = Math.max(1000, delaySeconds * 1000);

return new Promise((resolve) => setTimeout(() => resolve(items), delayMs));

const rows = [];
for (const item of items) {
  const value = item.json;
  if (Array.isArray(value)) rows.push(...value);
  else if (Array.isArray(value.items)) rows.push(...value.items);
  else if (Array.isArray(value.data)) rows.push(...value.data);
  else rows.push(value);
}

const seen = new Set();
const uniqueRows = [];
for (const row of rows) {
  const key = String(row.canonical_id || row.id || row.urn || row.url || row.postUrl || JSON.stringify(row).slice(0, 200));
  if (seen.has(key)) continue;
  seen.add(key);
  uniqueRows.push(row);
}

return [{
  json: {
    total_results: rows.length,
    unique_results: uniqueRows.length,
    sample_results: uniqueRows.slice(0, 20),
    collected_at: new Date().toISOString()
  }
}];
